 95→            >
 96→                Lancer une analyse
 97→            </button>
 98→        </div>
 99→    );
100→  }
101→
102→  const criticalRecs = data.recommendations.filter(r => r.priority === 'critical');
103→  const otherRecs = data.recommendations.filter(r => r.priority !== 'critical');
104→
105→  return (
106→    <div className="max-w-5xl mx-auto px-4 py-10 animate-in fade-in duration-500 pb-24">
