124→        </p>
125→      </div>
126→
127→      <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-8 gap-4 bg-purple-500/5 p-4 rounded-xl border border-white/10">
128→        <div>
129→            <p className="text-sm text-gray-400">{data.recommendations.length} points d'optimisation détectés</p>
130→        </div>
131→        <div className="flex items-center gap-3">
132→            <span className="text-xs px-2 py-1 bg-black/40 rounded border border-white/10 text-gray-400">
